extension StringCasing on String {
  String get capitalized =>
      isEmpty ? this : '${this[0].toUpperCase()}${substring(1)}';
}

void main() {
  print('hello'.capitalized); // Hello
}

String greet(String name,
    {String greeting = 'Hello', bool loud = false}) {
  final msg = '$greeting, $name';
  return loud ? msg.toUpperCase() : msg;
}

void main() {
  print(greet('Ada'));
  print(greet('Ada', greeting: 'Hi', loud: true));
}

class Logger {
  final String name;
  static final _cache = <String, Logger>{};

  Logger._internal(this.name);

  factory Logger(String name) =>
      _cache.putIfAbsent(name, () => Logger._internal(name));
}

void main() {
  print(identical(Logger('app'), Logger('app'))); // true
}

