(String, int) parse(String s) {
  final parts = s.split(':');
  return (parts[0], int.parse(parts[1]));
}

void main() {
  final (name, age) = parse('Ada:36');
  final label = switch (age) {
    >= 18 => 'adult',
    _ => 'minor',
  };
  print('$name is $label');
}

typedef Json = Map<String, dynamic>;
typedef Reducer<T> = T Function(T acc, T item);

T fold<T>(List<T> xs, T init, Reducer<T> f) {
  var acc = init;
  for (final x in xs) acc = f(acc, x);
  return acc;
}

void main() {
  print(fold<int>([1, 2, 3], 0, (a, b) => a + b)); // 6
}

